// Combine both TMDB result arrays, deduplicate by id, keep top 8 by popularity
const listA = $input.all()[0].json.results || [];
const listB = $input.all()[1]?.json?.results || [];

const seen = new Set();
const combined = [...listA, ...listB].filter(m => {
  if (seen.has(m.id)) return false;
  seen.add(m.id);
  return true;
});

const top = combined
  .sort((a, b) => b.popularity - a.popularity)
  .slice(0, 8);

return top.map(m => ({ json: m }));

// Merge TMDB detail + RapidAPI IMDB into a single clean movie object
const detail = $('TMDB – movie detail').first().json;
const imdb   = $('RapidAPI – IMDB data').first().json;

const posterUrl = detail.poster_path
  ? `https://image.tmdb.org/t/p/w780${detail.poster_path}`
  : null;

const topCast = (detail.credits?.cast || [])
  .slice(0, 3)
  .map(c => c.name)
  .join(', ');

const genres = (detail.genres || [])
  .map(g => g.name)
  .join(',');

const releaseYear = (detail.release_date || '').split('-')[0] || 'N/A';

const imdbRating = imdb.rating?.aggregate_rating ?? imdb.averageRating ?? 'N/A';

return [{
  json: {
    tmdb_id:      detail.id,
    imdb_id:      detail.imdb_id,
    title:        detail.title,
    overview:     detail.overview,
    genres:       genres,
    release_year: releaseYear,
    runtime:      detail.runtime,
    popularity:   detail.popularity,
    poster_url:   posterUrl,
    cast:         topCast,
    imdb_rating:  String(imdbRating),
    vote_count:   imdb.numVotes ?? detail.vote_count,
  }
}];

// Parse the S3 public URL printed to stdout by overlay.py
// and attach it alongside the existing movie fields
const s3Url = $json.stdout.trim();
const prev  = $('Enrich – merge fields').first().json;

if (!s3Url.startsWith('https://')) {
  throw new Error('overlay.py did not return a valid S3 URL. stderr: ' + $json.stderr);
}

return [{ json: { ...prev, s3_image_url: s3Url } }];

// Collect ALL enriched movies from all loop iterations
// The loop node merges them here automatically after the last batch
return $input.all().map(item => ({ json: item.json }));

// Parse theme JSON from OpenAI response
const raw = $json.message?.content || $json.choices?.[0]?.message?.content || '';
try {
  const parsed = JSON.parse(raw.replace(/```json|```/g, '').trim());
  return [{ json: parsed }];
} catch(e) {
  throw new Error('AI theme response was not valid JSON: ' + raw);
}

// Build the final Instagram post data object
const raw = $json.message?.content || $json.choices?.[0]?.message?.content || '';
const recs = JSON.parse(raw.replace(/```json|```/g, '').trim());
const themeData = $('Parse theme JSON').first().json;
const movies    = $('Collect all movies').all().map(i => i.json);

// Caption strategy: theme intro + top 3 current movies + 5 recs
const currentSection = movies.slice(0, 3).map((m, idx) =>
  `${['🥇','🥈','🥉'][idx]} *${m.title}* (${m.release_year}) — ⭐ ${m.imdb_rating}\n${m.genres.split(',').slice(0,2).join(' · ')}`
).join('\n\n');

const recsSection = recs.map((r, idx) =>
  `${idx+1}. *${r.title}* (${r.year}) — ${r.hook}`
).join('\n');

const hashtags = [
  '#movies', '#film', '#cinema', '#movienight', '#imdb',
  '#' + themeData.theme.replace(/\s+/g,''),
  '#nowplaying', '#filmrecommendations', '#moviestowatch', '#netflix'
].join(' ');

const caption = [
  `${themeData.emoji} This week's vibe: *${themeData.theme}*`,
  '',
  '🎬 Trending now:',
  currentSection,
  '',
  `💡 More picks for the theme:`,
  recsSection,
  '',
  hashtags
].join('\n');

return [{
  json: {
    theme:        themeData.theme,
    theme_emoji:  themeData.emoji,
    caption:      caption,
    hashtags:     hashtags,
    recs:         recs,
    movies:       movies,
    s3_urls:      movies.map(m => m.s3_image_url).filter(Boolean),
    created_at:   new Date().toISOString(),
  }
}];
